import datetimefrom libs.database.model import Modelfrom libs.database.types import Date, Number, Dateclass Processes(Model):    __tablename__ = 'processes'    id = Number(field="id")    date_created = Date(field="date_created", default=datetime.datetime.now())    date_modified = Date(field="date_modified")    user_id = Number(field="user_id")    tool_id = Number(field="tool_id")    tool_price = Number(field="tool_price")    items_total = Number(field="items_total")    items_finished = Number(field="items_finished")    date_finished = Date(field="date_finished")